CREATE TRIGGER [dbo].[WorkElementTypeAttributeListItem_History]ON [dbo].[WorkElementTypeAttributeListItem]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.WorkElementTypeAttributeListItemId IS NOT NULL AND d.WorkElementTypeAttributeListItemId IS NULL THEN 'I' 		WHEN i.WorkElementTypeAttributeListItemId IS NOT NULL AND d.WorkElementTypeAttributeListItemId IS NOT NULL THEN 'U' 		WHEN i.WorkElementTypeAttributeListItemId IS NULL AND d.WorkElementTypeAttributeListItemId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.WorkElementTypeAttributeListItemId = d.WorkElementTypeAttributeListItemId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_WorkElementTypeAttributeListItem([WorkElementTypeAttributeListItemId], [WorkElementTypeAttributeId], [Name], [Description], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [WorkElementTypeAttributeListItemId], [WorkElementTypeAttributeId], [Name], [Description], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_WorkElementTypeAttributeListItem([WorkElementTypeAttributeListItemId], [WorkElementTypeAttributeId], [Name], [Description], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [WorkElementTypeAttributeListItemId], [WorkElementTypeAttributeId], [Name], [Description], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND